import * as Sentry from "@sentry/browser";
import type { AnyFunction, MeasurementEnvironment } from "./types";
import { shouldMeasure, currentPerformanceLog, setCurrentPerformanceLog, isAggressiveLoggingEnabled } from "./environment";

/**
 * Wraps a function so that every call is measured as a Sentry transaction.
 * Sub-functions called during execution can be tracked as child spans using `measureSpan`.
 *
 * @param name – transaction name shown in Sentry (e.g. "malwarebytes.updateDatabases")
 * @param fn – the original function to measure
 * @param environment – environment where measurement should run ('beta' | 'stable' | 'all')
 * @param op – Sentry operation category
 * @returns wrapped function (preserves return value & async behaviour)
 *
 * @example
 *   // Wrap the top-level function to measure only in beta
 *   malwarebytes.updateDatabases = measureFunction(
 *     "malwarebytes.updateDatabases",
 *     malwarebytes.updateDatabases,
 *     "beta"
 *   );
 *
 *   // Inside sub-functions, explicitly specify environment for each span:
 *   async function fetchRemoteDb(url: string) {
 *     return measureSpan("fetchRemoteDb", { op: "http", environment: "beta" }, async () => {
 *       return await fetch(url);
 *     });
 *   }
 */
export function measureFunction<T extends AnyFunction>(
    name: string,
    fn: T,
    environment: MeasurementEnvironment = 'all',
    op: string = "function"
): T {
    // If environment doesn't match, return original function directly (zero overhead)
    if (!shouldMeasure(environment)) {
        return fn;
    }

    return function (this: any, ...args: Parameters<T>): ReturnType<T> {
        return Sentry.startSpan(
            { name, op, forceTransaction: true },
            () => {
                // Initialize performance logging in aggressive dev mode
                const isAggressiveLogging = isAggressiveLoggingEnabled();
                if (isAggressiveLogging) {
                    setCurrentPerformanceLog({
                        transaction: name,
                        spans: [],
                        startTime: performance.now()
                    });
                    console.log(`[Performance] Transaction started: ${name}`);
                }
                
                try {
                    const result = fn.apply(this, args);
                    
                    // Log performance summary if aggressive mode
                    if (isAggressiveLogging && currentPerformanceLog) {
                        const duration = performance.now() - currentPerformanceLog.startTime;
                        console.log(`[Performance] Transaction completed: ${currentPerformanceLog.transaction} (${duration.toFixed(2)}ms)`);
                        if (currentPerformanceLog.spans.length > 0) {
                            console.log(`[Performance] Sub-spans: ${currentPerformanceLog.spans.join(', ')}`);
                        }
                    }
                    
                    return result;
                } finally {
                    setCurrentPerformanceLog(null);
                }
            }
        );
    } as T;
}