import { chrome } from "../polyfill";
import { TARGET_BROWSER } from "../../app/scripts/browser-const.js";
import { BROWSER_NAME } from "@/app/scripts/app-consts.js";
import type { MeasurementEnvironment, PerformanceLogEntry } from "./types";

// Global variables injected by webpack DefinePlugin
declare const ENVIRONMENT: string;
declare const IS_SENTRY_DEV_MODE_AGGRESSIVE: boolean;

/**
 * Shared performance logging state
 */
export let currentPerformanceLog: PerformanceLogEntry | null = null;

/**
 * Set the current performance log entry
 */
export function setCurrentPerformanceLog(log: PerformanceLogEntry | null): void {
    currentPerformanceLog = log;
}

/**
 * Check if measurement should be enabled based on current environment
 */
export function shouldMeasure(targetEnvironment: MeasurementEnvironment): boolean {
    // Firefox: Never measure performance (following same pattern as Sentry exclusion)
    if (TARGET_BROWSER as string === BROWSER_NAME.Firefox) {
        return false;
    }

    if (targetEnvironment === 'all') {
        return true;
    }

    // Check if we're in production environment (both beta and stable are production)
    // eslint-disable-next-line no-undef
    if (typeof ENVIRONMENT === 'undefined' || ENVIRONMENT !== 'production') {
        return false;
    }

    // Detect if this is a beta version
    let isBetaVersion = false;
    try {
        const manifest = chrome.runtime.getManifest();
        isBetaVersion = manifest.name.includes('Beta');
    } catch (e) {
        // If we can't detect, assume stable
        isBetaVersion = false;
    }

    const result = targetEnvironment === (isBetaVersion ? 'beta' : 'stable');
    return result;
}

/**
 * Check if aggressive performance logging is enabled
 */
export function isAggressiveLoggingEnabled(): boolean {
    // eslint-disable-next-line no-undef
    return typeof IS_SENTRY_DEV_MODE_AGGRESSIVE !== 'undefined' && IS_SENTRY_DEV_MODE_AGGRESSIVE === true;
}