import {chrome} from "../../../utils/polyfill.ts";
import {MV2ExclusionHandler} from "./exclusions-mv2";
import {EXCLUSION_ADS, EXCLUSION_MALWARE, EXCLUSION_SCAMS} from "../app-consts";
import {
    allResourceTypes,
    DYNAMIC_RULE_ADS_PRIORITY,
    DYNAMIC_RULE_ALL_PRIORITY,
    DYNAMIC_RULE_TEMPORARY_PRIORITY,
    DYNAMIC_RULE_MALWARE_PRIORITY,
    getExistingDynamicRulesByActionTypes,
    getExistingDynamicRules,
    getExistingSessionRules,
    getNextDynamicRuleId,
    getNextSessionRuleId,
    mainFrameResourceType,
    DYNAMIC_RULE_SCAMS_PRIORITY,
    allSupportedResourceTypes
} from '../mv3/dynamic-rule-utils';

import{ handleExcludedHost } from '@/app/scripts/app.js';
export class MV3ExclusionHandler extends MV2ExclusionHandler {
    constructor() {
        super();
        this.TEMPORARY_EXCLUSIONS = {};
        this.loadTemporaryExclusions();
    }

    extractExclusions(exclusions) {
        if (Array.isArray(exclusions)) {
            return exclusions;
        }
        return exclusions.split(',');
    }

    exportExclusions() {
        return {};
    }

    async importExclusions(exclusionItems) {

        // add all items from the list
        for (let i = 0; i < Object.keys(exclusionItems).length; i++) {
            const host = Object.keys(exclusionItems)[i];
            const exclusions = await this.exclude_mapIntsToExclusions(exclusionItems[host]);
            await handleExcludedHost(host, exclusions, true, (result) => {
                if(result.error) {
                    console.error('Error adding exclusion: ', result.error);
                    throw new Error('Error adding exclusion: ', result.error);
                } else {
                    console.log('Exclusion added successfully: ', result);
                }
            });            
        }
    }

    getPriorityForExclusions(exclusions) {
        let priority = DYNAMIC_RULE_ALL_PRIORITY;
        if (!exclusions) {
            return priority;
        }

        let individualExclusions;
        if (Array.isArray(exclusions)) {
            individualExclusions = exclusions;
        } else {
            individualExclusions = exclusions.split(',');
        }

        if (individualExclusions.length == 1 && individualExclusions.includes(EXCLUSION_ADS)) {
            priority = DYNAMIC_RULE_ADS_PRIORITY;
        } else if (individualExclusions.length == 1 && individualExclusions.includes(EXCLUSION_MALWARE)) {
            priority = DYNAMIC_RULE_MALWARE_PRIORITY;
        } else if (individualExclusions.length == 1 && individualExclusions.includes(EXCLUSION_SCAMS)) {
            priority = DYNAMIC_RULE_SCAMS_PRIORITY;
        }
        return priority;
    }

    async exclude(host, exclusions) {
        // regardless of the exclusion, exclude for all types
        console.debug('MV3: EXCLUDE: ', host, exclusions);
        let result;
        if (Array.isArray(exclusions)) {
            result = await super.exclude(host, exclusions.join(','));
        } else {
            result = await super.exclude(host, exclusions);
        }
        if (await this.whitelistRuleExistsForHost(host, exclusions)) {
            return result;
        }

        // Parse exclusions to handle both single and multiple types
        let individualExclusions;
        if (Array.isArray(exclusions)) {
            individualExclusions = exclusions;
        } else {
            individualExclusions = exclusions.split(',');
        }

        let rules = [];

        // Process each exclusion type and combine all rules
        for (let i = 0; i < individualExclusions.length; i++) {
            const exclusionType = individualExclusions[i];
            let priority = this.getPriorityForExclusions(exclusionType);

            if (exclusionType === EXCLUSION_ADS) {
                // add 1 rule for main frame blocks and another rule to whitelist all the sub frame requests from this host
                const adsRules = [
                    {
                        priority: priority,
                        action: {
                            type: 'allow'
                        },
                        condition: {
                            urlFilter: host,
                            resourceTypes: allResourceTypes
                        }
                    },
                    {
                        priority: priority,
                        action: {
                            type: 'allow'
                        },
                        condition: {
                            urlFilter: '*',
                            initiatorDomains: [host],
                            resourceTypes: allResourceTypes
                        }
                    },
                    {
                        priority: priority,
                        action: { type: 'allowAllRequests' },
                        condition: {
                            initiatorDomains: [host],
                            resourceTypes: [ "main_frame", "sub_frame" ]
                        }
                    }
                ];
                rules.push(...adsRules);
            } else if (exclusionType === EXCLUSION_MALWARE) {
                const malwareRules = await this.getCounterRulesForHost(host); // Array of rules customized for this host of type malware.
                rules.push(...malwareRules);
            } else if (exclusionType === EXCLUSION_SCAMS) {
                const scamsRules = [ // 1 dummy rule. since no DNRs for scams, just to reserve the exclusion for host,
                    {
                        priority: priority, // = 1, scams doesnt have DNRs, keep 1 for compatibility
                        action: {
                            type: 'allow'
                        },
                        condition: {
                            urlFilter: host,
                            resourceTypes: allResourceTypes
                        }
                    }
                ];
                rules.push(...scamsRules);
            }
        }

        // Assign IDs to all rules that don't have them
        let currentRuleId = await getNextDynamicRuleId();
        for (const rule of rules) {
            rule.id = ++currentRuleId;
        }

        console.debug('MV3: ADD RULE: ', rules);
        // update dynamic rules
        console.debug('MV3_updateDynamicRulesStart: ', new Date().toString());
        await chrome.declarativeNetRequest.updateDynamicRules({
            addRules: [...rules], // Rule[]
            removeRuleIds: [], // number[]
        });
        console.debug('MV3_updateDynamicRulesEnd: ', new Date().toString());
        return result;
    }


    /**
     * Creates counter-rules with higher priority to make malware rules inactive for a specific host.
     * Reads the malware JSON file and creates allow rules that override malware blocking for the given host.
     * @param {string} host - The host to create counter-rules for (e.g., "example.com")
     * @returns {Promise<Array>} Array of counter-rules with "allow" actions
     */
    async getCounterRulesForHost(host) {
        const malwareStaticRulesUrl = chrome.runtime.getURL("db/mbgc.mv3.malware_1.json");
        
        const staticRuleFetch = async (url) => {
            const options = {};
            options.method = options.method || "GET";
            options.headers = options.headers || {};
            options.headers["pragma"] = "no-cache";
            options.headers["cache-control"] = "no-cache, no-store";

            const response = await fetch(url, options);
            return response.json();
        };

        const malwareStaticRules = await staticRuleFetch(malwareStaticRulesUrl);
        
        // Get priority for malware exclusions (should be higher than static malware rules)
        const counterPriority = this.getPriorityForExclusions(EXCLUSION_MALWARE);
        
        const counterRules = [];
        let ruleId = await getNextDynamicRuleId();
        
        // Create a counter-rule for every malware rule in the JSON file
        for (const malwareRule of malwareStaticRules) {
            if (malwareRule.action?.type === "block" || malwareRule.action?.type === "redirect") {
                // Create a specific counter-rule that overrides this malware rule
                const counterRule = {
                    id: ruleId++,
                    priority: counterPriority,
                    action: {
                        type: "allow"  // Override block/redirect with allow
                    },
                    condition: {
                        urlFilter: malwareRule.condition.urlFilter, // Same URL filter as original
                        resourceTypes: malwareRule.condition.resourceTypes, // Same resource types
                        initiatorDomains: [host] // Make it specific to this host
                    }
                };
                
                counterRules.push(counterRule);
            }
        }
        
        console.debug(`GCRF: Generated ${counterRules.length} counter-rules for malware exclusion of ${host} (from ${malwareStaticRules.length} total malware rules)`);
        return counterRules;
    }

    async getExclusions() {
        const exclusions = await super.getExclusions();
        const whitelistRules = await this.getExistingWhitelistDynamicRules();

        const allowedHostsSet = new Set();
        for (const r of whitelistRules) {
            if (r.condition.initiatorDomains && r.condition.initiatorDomains.length > 0) {
                r.condition.initiatorDomains.forEach((val) => allowedHostsSet.add(val));
            } else if (r.condition.urlFilter && r.condition.urlFilter !== '*') {
                allowedHostsSet.add(r.condition.urlFilter);
            }
        }
        const allowedHosts = Array.from(allowedHostsSet);
        const entriesWithCorrespondingRule = Object.entries(exclusions).filter(([host]) => {
            return allowedHosts.includes(host);
        });
        return Object.fromEntries(entriesWithCorrespondingRule);
    }

    async getExclusions_getExclusionsByNames(hostNames) {
        if (Object.keys(hostNames).length === 0) {
            hostNames = [];
        }

        const exclusions = await super.getExclusions_getExclusionsByNames(hostNames);
        console.debug('HOSTNAMES: HOSTNAMES=', {hostNames, exclusions});

        hostNames = hostNames.map((h) => h.toLowerCase());
        const whitelistRules = await this.getExistingWhitelistDynamicRules();

        const allowedHostsSet = new Set();
        for (const r of whitelistRules) {
            if (r.condition.urlFilter && hostNames.includes(r.condition.urlFilter)) {
                allowedHostsSet.add(r.condition.urlFilter);
            } else if (r.condition.initiatorDomains && r.condition.initiatorDomains.length > 0) {
                r.condition.initiatorDomains.forEach((val) => allowedHostsSet.add(val));
            }
        }
        const allowedHosts = Array.from(allowedHostsSet);
        const entriesWithCorrespondingRule = Object.entries(exclusions).filter(([host]) => {
            return allowedHosts.includes(host);
        });
        return Object.fromEntries(entriesWithCorrespondingRule);
    }

    async removeAllExclusions() {
        const exclusionsIndex = await super.removeAllExclusions();
        // remove dynamic rules
        const rules = await this.getExistingWhitelistDynamicRules();
        const ruleIds = rules.map((r) => r.id);
        await chrome.declarativeNetRequest.updateDynamicRules({
            addRules: [], // Rule[]
            removeRuleIds: [...ruleIds], // number[]
        });
        return exclusionsIndex;
    }

    async removeExclude(host, exclusions, addOverride) {
        console.debug('REMOVE EXCLUSIONS: ', {host, exclusions, addOverride});
        const res = await super.removeExclude(host, exclusions, addOverride);
        console.debug('REMOVE EXCLUSIONS RESULT_0: ', res);
        const rules = await this.getExistingWhitelistDynamicRules();
        const idsToRemove = [];

        for (const rule of rules) {
            if (this._whitelistRuleAffectsHost(rule, host) &&
                rule.priority === this.getPriorityForExclusions(exclusions)) {
                idsToRemove.push(rule.id);
            }
        }

        // update dynamic rules
        await chrome.declarativeNetRequest.updateDynamicRules({
            addRules: [], // Rule[]
            removeRuleIds: [...idsToRemove], // number[]
        });

        const remainingDynamicRules = await this.getExistingWhitelistDynamicRules();
        console.debug('REMAINING WL DYNAMIC RULES: ', remainingDynamicRules);

        return res;
    }

    async removeExclusions(host) {
        const res = await super.removeExclusions(host);
        console.debug('REMOVE EXCLUSIONS RESULT_1: ', res);

        const rules = await this.getExistingWhitelistDynamicRules();
        const idsToRemove = [];

        for (const rule of rules) {
            if (this._whitelistRuleAffectsHost(rule, host)) {
                idsToRemove.push(rule.id);
            }
        }

        // update dynamic rules
        await chrome.declarativeNetRequest.updateDynamicRules({
            addRules: [], // Rule[]
            removeRuleIds: [...idsToRemove], // number[]
        });
        return res;
    }

    async loadTemporaryExclusions() {
        const rules = await getExistingSessionRules();

        for (const rule of rules) {
            if (rule.condition.initiatorDomains && rule.condition.tabIds) {
                for (const tabId of rule.condition.tabIds) {
                    this.TEMPORARY_EXCLUSIONS[tabId] = rule.condition.initiatorDomains;
                }
            }
        }
    }

    async excludeTemporarily(host, tabId) {
        // If there is a DYNAMIC whitelist rule for this host, It takes precedence over any session-scoped rules
        // So we don't need to add another rule
        if (await this.whitelistRuleExistsForHost(host)) {
            console.debug('EXCLUDE_TEMP: WHITELIST RULE EXISTS FOR HOST: ', {host});
            return;
        }

        tabId = +tabId;

            
        console.debug('EXCLUDE_TEMP: TABID: ', {tabId});
        // add 1 rule for main frame blocks and another rule to whitelist all the sub frame requests from this host
        const rules = [
            {
                id: await getNextSessionRuleId(),
                priority: DYNAMIC_RULE_TEMPORARY_PRIORITY,
                action: {
                    type: 'allow'
                },
                condition: {
                    urlFilter: host,
                    resourceTypes: allResourceTypes,
                    tabIds: [tabId],
                }
            },
            {
                id: await getNextSessionRuleId(),
                priority: DYNAMIC_RULE_TEMPORARY_PRIORITY,
                action: {
                    type: 'allow'
                },
                condition: {
                    urlFilter: '*',
                    initiatorDomains: [host],
                    resourceTypes: allResourceTypes,
                    tabIds: [tabId],
                }
            },
        ];
        console.debug('MV3: ADD RULE: ', rules);
        await chrome.declarativeNetRequest.updateSessionRules({
            addRules: [...rules], // Rule[]
            removeRuleIds: [], // number[]
        });

        if (this.TEMPORARY_EXCLUSIONS[tabId]) {
            this.TEMPORARY_EXCLUSIONS[tabId] = Array.from(new Set([...(this.TEMPORARY_EXCLUSIONS[tabId]), host]));
        } else {
            this.TEMPORARY_EXCLUSIONS[tabId] = [host];
        }
    }

    isTemporarilyExcluded(host, tabId) {
        if (!this.TEMPORARY_EXCLUSIONS[tabId]) {
            return false;
        }
        return this.TEMPORARY_EXCLUSIONS[tabId].includes(host);
    }

    ////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
    ///////////////////////////////////////////////////END PUBLIC INTERFACE ////////////////////////////////////////////
    ////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

    _whitelistRuleAffectsHost(rule, host) {
        if (rule.condition.urlFilter && rule.condition.urlFilter === host) {
            return true;
        } else if (rule.condition.initiatorDomains &&
            rule.condition.initiatorDomains.length > 0 &&
            rule.condition.initiatorDomains.includes(host)) {
            return true;
        } else if (rule.condition.requestDomains && rule.condition.requestDomains.length > 0 &&
            rule.condition.requestDomains.includes(host)) {
            return true;
        }
        return false;
    }

    async whitelistRuleExistsForHost(host, exclusions) {
        const existingDynamicRules = await this.getExistingWhitelistDynamicRules();
        for (const rule of existingDynamicRules) {
            if (this._whitelistRuleAffectsHost(rule, host) &&
                rule.priority === this.getPriorityForExclusions(exclusions)) {
                return true;
            }
        }
        return false;
    }

    async getExistingWhitelistDynamicRules() {
        return getExistingDynamicRulesByActionTypes(['allow', 'allowAllRequests'], [
            DYNAMIC_RULE_ADS_PRIORITY, 
            DYNAMIC_RULE_MALWARE_PRIORITY, 
            DYNAMIC_RULE_SCAMS_PRIORITY, 
            DYNAMIC_RULE_ALL_PRIORITY
        ]);
    }

    /**
     * Add a granular allow item to the allow list.
     * Triggred by item: three dots -> "Allow on this website" option in the popup.
     * param is object {host, priority, tracker}
     * @param {Object} rule - {host, priority, tracker}
     * @returns {Promise<void>}
     */
    async addIndividualExclusion(rule) {
        const { host, priority, tracker } = rule;   
        const newRule = {
            id: await getNextDynamicRuleId(),
            priority,
            action: {
                type: 'allow',
            },
            condition: {
                initiatorDomains: [host],
                urlFilter: `||${tracker}^`,
                resourceTypes: allSupportedResourceTypes(),
            }
        };
        console.debug('MV3: ADDING GRANULAR ALLOW RULE: ', newRule);
        await chrome.declarativeNetRequest.updateDynamicRules({
            addRules: [newRule], // Rule[]
            removeRuleIds: [], // number[]
        });
    }

    /**
     * Remove a granular allow item from the allow list.
     * Triggered by item: three dots -> "Block on this website" option in the popup.
     * param is object {host, priority, tracker}
     * @param {Object} rule - {host, priority, tracker}
     * @returns {Promise<void>}
     */
    async removeIndividualExclusion(rule) {
        const { host, priority, tracker } = rule;
        const dynamicRulesWithSamePriority = await getExistingDynamicRules(priority)
        const rulesToRemove = dynamicRulesWithSamePriority.filter((r) => {
            return r?.condition?.initiatorDomains.includes(host) &&
                r?.condition?.urlFilter === `||${tracker}^`;
        }).map((r) => r.id);
        console.debug('MV3: REMOVING GRANULAR ALLOW RULE ID: ', rulesToRemove, rule);
        await chrome.declarativeNetRequest.updateDynamicRules({
            addRules: [],
            removeRuleIds: rulesToRemove,
        });
    }
    
    getExclusionsSnapshot() {
        return this.EXCLUSIONS;
    }
}
