import * as Sentry from "@sentry/browser";
import {chrome} from "../polyfill.ts";
import { TARGET_BROWSER } from "@/app/scripts/browser-const.js";
import { BROWSER_NAME } from "@/app/scripts/app-consts.js";

export function sentryInit(_options = {}) {
    if (TARGET_BROWSER !== BROWSER_NAME.Firefox) {
        console.debug('sentryInit. ENVIRONMENT: ', ENVIRONMENT);

        // Detect manifest metadata
        let manifest = {};
        let isBetaVersion = false;
        try {
            manifest = chrome.runtime.getManifest();
            isBetaVersion = manifest.name.includes('Beta');
        } catch (e) {
            console.warn('sentryInit: Could not get manifest.', e);
        }

        // Environment detection
        // ENVIRONMENT is injected by webpack DefinePlugin from argv.mode
        // IS_SENTRY_DEV_MODE_AGGRESSIVE is injected from process.env.IS_SENTRY_DEV_MODE_AGGRESSIVE
        // eslint-disable-next-line no-undef
        const isAggressiveDevMode = IS_SENTRY_DEV_MODE_AGGRESSIVE === true;
        const IGNOREED_SHORT_TRANSACTIONS_MS = 10;

        // Sampling rates (per-environment)
        // Dev (aggressive): 100% — captures every event and transaction for local debugging
        // Dev (normal):       0% — Sentry is disabled entirely; nothing leaves the machine
        // Beta:            varied — enough signal to catch regressions without overwhelming quota
        // Production:        low — minimal overhead for the end-user base
        const sampleRate = isAggressiveDevMode ? 1.0 : (isBetaVersion ? 0.1 : 0.005);
        const tracesSampleRate = isAggressiveDevMode ? 1.0 : (isBetaVersion ? 0.01 : 0.00025);
        const profilesSampleRate = isAggressiveDevMode ? 1.0 : (isBetaVersion ? 0.02 : 0.0005);

        // In normal dev mode, Sentry is completely disabled (enabled: false).
        // In production / beta it is always enabled.
        // In aggressive dev mode it is enabled with 100% sampling.
        const enabled = isAggressiveDevMode || ENVIRONMENT === 'production';

        const params = {
            dsn: "https://708a324f1a7ec87a2658346fb4bb7586@o438337.ingest.sentry.io/4506062147551232",
            enabled,
            debug: isAggressiveDevMode,
            release: manifest.version,
            attachStacktrace: true,
            sampleRate,
            tracesSampleRate,
            profilesSampleRate,
            replaysSessionSampleRate: 0,
            replaysOnErrorSampleRate: 0,

            beforeSend(event) {
                if (!event.contexts) {
                    event.contexts = {};
                }
                event.contexts.extension = {
                    version: manifest.version,
                    browser: TARGET_BROWSER,
                    environment: ENVIRONMENT,
                    is_beta: isBetaVersion,
                    manifest_version: manifest.manifest_version
                };
                return event;
            },

            beforeSendTransaction(transaction) {
                // Enrich transaction with extension context
                if (!transaction.contexts) {
                    transaction.contexts = {};
                }
                transaction.contexts.extension = {
                    version: manifest.version,
                    browser: TARGET_BROWSER,
                    environment: ENVIRONMENT,
                    is_beta: isBetaVersion,
                    manifest_version: manifest.manifest_version
                };

                // Filter out very short transactions (< 10ms) to reduce noise
                if (transaction.timestamp && transaction.start_timestamp) {
                    const durationMs = (transaction.timestamp - transaction.start_timestamp) * 1000;
                    if (durationMs < IGNOREED_SHORT_TRANSACTIONS_MS) {
                        return null;
                    }
                }

                return transaction;
            },

            ignoreErrors: [
                'Could not establish connection. Receiving end does not exist',
                'No tab with id:',
                'Failed to fetch',
                'Corruption: block checksum mismatch',
                'QuotaExceededError: Encountered full disk',
                'Non-Error promise rejection captured with value: IO error',
                'FILE_ERROR_NO_SPACE',
                'FILE_ERROR_IO',
                'FILE_ERROR_FAILED',
                'FILE_ERROR_ACCESS_DENIED',
            ]
        };

        if (isBetaVersion || isAggressiveDevMode) {
            // eslint-disable-next-line max-len
            console.debug(`Sentry — env: ${ENVIRONMENT}, beta: ${isBetaVersion}, aggressiveDev: ${isAggressiveDevMode}, sampleRate: ${sampleRate}, tracesSampleRate: ${tracesSampleRate}`);
        }

        Sentry.init(params);

        // Global tags for filtering in the Sentry dashboard
        Sentry.setTag('extension.version', manifest.version);
        Sentry.setTag('extension.browser', TARGET_BROWSER);
        Sentry.setTag('extension.is_beta', isBetaVersion);
        Sentry.setTag('extension.environment', ENVIRONMENT);
        Sentry.setTag('extension.manifest_version', manifest.manifest_version);
    }
}
