import * as Sentry from "@sentry/browser";
import type { MeasureSpanOptions } from "./types";
import { shouldMeasure, currentPerformanceLog, isAggressiveLoggingEnabled } from "./environment";

/**
 * Runs `callback` inside a child span of the current active transaction.
 * If no transaction is active the callback still executes (Sentry will just
 * create a standalone span, or a no-op if tracing is off).
 *
 * @param name – span description (e.g. "parseEasyList")
 * @param options – extra Sentry span options including environment
 * @param callback – the work to measure (can be async)
 * @returns whatever `callback` returns
 *
 * @example
 *   const result = await measureSpan("parseEasyList", { op: "parse", environment: "beta" }, () => {
 *     return parseList(raw);
 *   });
 */
export function measureSpan<T>(
    name: string,
    options: MeasureSpanOptions = {},
    callback: () => T
): T {
    // If environment doesn't match, run callback directly (zero overhead)
    if (options.environment && !shouldMeasure(options.environment)) {
        return callback();
    }

    // Log span in aggressive dev mode
    const isAggressiveLogging = isAggressiveLoggingEnabled();
    if (isAggressiveLogging && currentPerformanceLog) {
        currentPerformanceLog.spans.push(name);
        console.log(`[Performance] Span started: ${name} (op: ${options.op || 'function'})`);
    }

    return Sentry.startSpan(
        { name, op: options.op || "function", attributes: options.attributes },
        () => callback()
    );
}